import{_ as o,c as i,o as a,a8 as l}from"./chunks/framework.BrmF0WDH.js";const u=JSON.parse('{"title":"03-Editor编辑器状态流","description":"","frontmatter":{},"headers":[],"relativePath":"onboarding/03-Editor编辑器状态流/index.md","filePath":"onboarding/03-Editor编辑器状态流/index.md","lastUpdated":1777649372000}'),d={name:"onboarding/03-Editor编辑器状态流/index.md"};function r(c,e,t,n,h,p){return a(),i("div",null,e[0]||(e[0]=[l('<h1 id="_03-editor编辑器状态流" tabindex="1">03-Editor编辑器状态流 <a class="header-anchor" href="#_03-editor编辑器状态流" aria-label="Permalink to &quot;03-Editor编辑器状态流&quot;">​</a></h1><h2 id="先看编辑器真正管理的是什么" tabindex="1">先看编辑器真正管理的是什么 <a class="header-anchor" href="#先看编辑器真正管理的是什么" aria-label="Permalink to &quot;先看编辑器真正管理的是什么&quot;">​</a></h2><p><code>packages/editor</code> 并不是一个“纯 UI 包”，它本质上是编辑态状态机。</p><p>其中最重要的是 <code>EditorService.state</code>，里面维护了：</p><ul><li><code>root</code><ul><li>当前整棵 Schema 树</li></ul></li><li><code>page</code><ul><li>当前编辑页面</li></ul></li><li><code>node</code><ul><li>当前主选中节点</li></ul></li><li><code>nodes</code><ul><li>当前多选节点列表</li></ul></li><li><code>parent</code><ul><li>当前选中节点的父节点</li></ul></li><li><code>sandbox</code><ul><li>当前画布实例 <code>BoxCore</code></li></ul></li><li><code>pageLength</code><ul><li>页面数量</li></ul></li></ul><h2 id="入口组件如何把这些服务串起来" tabindex="1">入口组件如何把这些服务串起来 <a class="header-anchor" href="#入口组件如何把这些服务串起来" aria-label="Permalink to &quot;入口组件如何把这些服务串起来&quot;">​</a></h2><p><code>packages/editor/src/editor.vue</code> 做了三件事：</p><ol><li>组装布局组件</li><li>初始化 service</li><li>通过 <code>provide</code> 把 service 暴露给子组件</li></ol><p><code>useServicesInit</code> 则负责把外部 props 映射到内部状态，例如：</p><ul><li><code>props.value -&gt; editorService.root</code></li><li><code>props.boxRect -&gt; uiService.sandboxRect</code></li><li><code>props.componentGroupList -&gt; componentService.list</code></li></ul><p>这意味着外部应用传进来的 props，最终都会沉淀为 service 状态。</p><h2 id="编辑器里的-增删改查-本质是什么" tabindex="1">编辑器里的“增删改查”本质是什么 <a class="header-anchor" href="#编辑器里的-增删改查-本质是什么" aria-label="Permalink to &quot;编辑器里的“增删改查”本质是什么&quot;">​</a></h2><h3 id="新增节点" tabindex="1">新增节点 <a class="header-anchor" href="#新增节点" aria-label="Permalink to &quot;新增节点&quot;">​</a></h3><p><code>EditorService.add</code> 的核心动作：</p><ol><li>生成要新增的节点配置</li><li>找到父节点</li><li>把节点插入 <code>root</code> 配置树</li><li>调 <code>sandbox.add</code> 同步给 iframe</li><li>修正初始位置</li><li>更新选中状态和历史记录</li></ol><p>这里最重要的点是：</p><p>编辑器先改自己的 Schema，再通知 runtime 补齐渲染，不是反过来。</p><h3 id="更新节点" tabindex="1">更新节点 <a class="header-anchor" href="#更新节点" aria-label="Permalink to &quot;更新节点&quot;">​</a></h3><p><code>EditorService.update</code> 会：</p><ol><li>根据 <code>field</code> 找到原节点</li><li>合并配置</li><li>处理布局切换、副作用字段</li><li>回写到 <code>root</code></li><li>调 <code>sandbox.update</code></li><li>推入历史记录</li></ol><h3 id="删除节点" tabindex="1">删除节点 <a class="header-anchor" href="#删除节点" aria-label="Permalink to &quot;删除节点&quot;">​</a></h3><p><code>EditorService.delete</code> 会：</p><ol><li>从 <code>root</code> 里删掉节点</li><li>调 <code>sandbox.delete</code></li><li>重新计算默认选中项</li><li>更新历史记录</li></ol><p>所以编辑器和画布始终保持“配置树 + iframe 视图”的双写同步。</p><h2 id="为什么说-editorservice-是真正的编辑入口" tabindex="1">为什么说 <code>EditorService</code> 是真正的编辑入口 <a class="header-anchor" href="#为什么说-editorservice-是真正的编辑入口" aria-label="Permalink to &quot;为什么说 `EditorService` 是真正的编辑入口&quot;">​</a></h2><p>因为几乎所有编辑操作最终都要收束到这里：</p><ul><li>组件面板拖入</li><li>图层面板点击</li><li>属性面板修改</li><li>右键菜单操作</li><li>撤销重做</li><li>复制粘贴</li></ul><p>如果你在做需求时找不到入口，大概率先找 <code>EditorService</code>。</p><h2 id="历史记录怎么做" tabindex="1">历史记录怎么做 <a class="header-anchor" href="#历史记录怎么做" aria-label="Permalink to &quot;历史记录怎么做&quot;">​</a></h2><p><code>HistoryService</code> 是按页面维度存历史的。</p><p>核心做法是：</p><ul><li>每个页面对应一个 <code>UndoRedo&lt;StepValue&gt;</code></li><li><code>StepValue</code> 里不仅存页面数据，还存 <code>modifiedNodeFields</code> 和当前选中节点</li></ul><p>这样撤销重做不会只恢复“页面树”，还会尽量恢复编辑上下文。</p><p>这个设计是合理的，因为低代码编辑器里“当前选中了谁”本身就是编辑体验的一部分。</p><h2 id="属性面板为什么能动态变化" tabindex="1">属性面板为什么能动态变化 <a class="header-anchor" href="#属性面板为什么能动态变化" aria-label="Permalink to &quot;属性面板为什么能动态变化&quot;">​</a></h2><p>项目没有把属性面板写死，而是走组件元数据驱动。</p><p>例如 <code>packages/ui/src/config.ts</code> 暴露了：</p><ul><li><code>formSchemas</code></li><li><code>events</code></li></ul><p>每个组件的 <code>formSchema.ts</code> 定义这个组件有哪些可配置项、用什么表单组件渲染、有什么默认值。</p><p>所以属性面板不是静态写的，而是“读取组件元数据后动态生成”。</p><h2 id="组件面板和属性面板为什么是分开的" tabindex="1">组件面板和属性面板为什么是分开的 <a class="header-anchor" href="#组件面板和属性面板为什么是分开的" aria-label="Permalink to &quot;组件面板和属性面板为什么是分开的&quot;">​</a></h2><p>这是项目一个很重要的分层：</p><ul><li><code>componentService</code><ul><li>管左侧“能拖哪些组件”</li></ul></li><li><code>propsService</code><ul><li>管右侧“当前组件有哪些可编辑配置”</li></ul></li></ul><p>这样业务方扩展时，可以分别定制：</p><ul><li>可新增组件集合</li><li>每个组件的配置表单</li></ul><h2 id="编辑器这一层最容易踩的坑" tabindex="1">编辑器这一层最容易踩的坑 <a class="header-anchor" href="#编辑器这一层最容易踩的坑" aria-label="Permalink to &quot;编辑器这一层最容易踩的坑&quot;">​</a></h2><h3 id="_1-只改了-iframe-没改-root" tabindex="1">1. 只改了 iframe，没改 <code>root</code> <a class="header-anchor" href="#_1-只改了-iframe-没改-root" aria-label="Permalink to &quot;1. 只改了 iframe，没改 `root`&quot;">​</a></h3><p>这样刷新或重新选中后，状态会回滚。</p><h3 id="_2-只改了-root-没同步-sandbox" tabindex="1">2. 只改了 <code>root</code>，没同步 sandbox <a class="header-anchor" href="#_2-只改了-root-没同步-sandbox" aria-label="Permalink to &quot;2. 只改了 `root`，没同步 sandbox&quot;">​</a></h3><p>这样数据是对的，但画布不会立即反映。</p><h3 id="_3-更新时没保住-field" tabindex="1">3. 更新时没保住 <code>field</code> <a class="header-anchor" href="#_3-更新时没保住-field" aria-label="Permalink to &quot;3. 更新时没保住 `field`&quot;">​</a></h3><p>一旦 <code>field</code> 变了，选中、定位、事件命名空间都会跟着失效。</p><h2 id="新人第一次改编辑器需求的推荐入口" tabindex="1">新人第一次改编辑器需求的推荐入口 <a class="header-anchor" href="#新人第一次改编辑器需求的推荐入口" aria-label="Permalink to &quot;新人第一次改编辑器需求的推荐入口&quot;">​</a></h2><h3 id="需求属于结构操作" tabindex="1">需求属于结构操作 <a class="header-anchor" href="#需求属于结构操作" aria-label="Permalink to &quot;需求属于结构操作&quot;">​</a></h3><p>先看 <code>EditorService</code></p><h3 id="需求属于画布交互" tabindex="1">需求属于画布交互 <a class="header-anchor" href="#需求属于画布交互" aria-label="Permalink to &quot;需求属于画布交互&quot;">​</a></h3><p>先看 <code>packages/editor/src/components/layouts/sandbox/index.vue</code></p><h3 id="需求属于表单配置" tabindex="1">需求属于表单配置 <a class="header-anchor" href="#需求属于表单配置" aria-label="Permalink to &quot;需求属于表单配置&quot;">​</a></h3><p>先看 <code>packages/ui/src/**/formSchema.ts</code> 和 <code>propsService</code></p>',59)]))}const b=o(d,[["render",r]]);export{u as __pageData,b as default};
